{"code": "import json
import re

# Get CDH1 mutations data
cdh1_var = 'var_functions.query_db:46'
cdh1_path = locals()[cdh1_var]

with open(cdh1_path, 'r') as f:
    cdh1_mutations = json.load(f)

# Get breast cancer clinical data
breast_clinical_var = 'var_functions.query_db:32'
breast_clinical_path = locals()[breast_clinical_var]

with open(breast_clinical_path, 'r') as f:
    breast_clinical_data = json.load(f)

# Extract all breast cancer barcodes and their histology types
breast_barcodes = set()
barcode_to_histology = {}
for record in breast_clinical_data:
    desc = record['Patient_description']
    hist_type = record['histological_type']

    barcode_match = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', desc)
    if barcode_match:
        barcode = barcode_match.group(1)
        breast_barcodes.add(barcode)
        barcode_to_histology[barcode] = hist_type

# Find CDH1 mutations in breast cancer patients
breast_cdh1_mutations = {}
for mutation in cdh1_mutations:
    barcode = mutation['ParticipantBarcode']
    if barcode in breast_barcodes:
        breast_cdh1_mutations[barcode] = int(mutation['mutation_count'])

print('Total breast cancer patients:', len(breast_barcodes))
print('Breast cancer patients with CDH1 mutations:', len(breast_cdh1_mutations))
print('Sample CDH1 mutated patients:', list(breast_cdh1_mutations.keys())[:10])

# Create histology groups
histology_groups = {}
for barcode in breast_barcodes:
    hist_type = barcode_to_histology[barcode]
    if hist_type not in histology_groups:
        histology_groups[hist_type] = {'total': 0, 'cdh1_mutated': 0}
    histology_groups[hist_type]['total'] += 1
    if barcode in breast_cdh1_mutations:
        histology_groups[hist_type]['cdh1_mutated'] += 1

# Filter out histology types with total <= 10 and show distribution
filtered_groups = {}
for hist, counts in histology_groups.items():
    if counts['total'] > 10:
        filtered_groups[hist] = counts
        print(f"{hist}: {counts['cdh1_mutated']} mutated, {counts['total'] - counts['cdh1_mutated']} wild-type, total {counts['total']}")

print('__RESULT__:')
print(json.dumps({
    'total_breast_patients': len(breast_barcodes),
    'cdh1_mutated_patients': len(breast_cdh1_mutations),
    'histology_groups': filtered_groups
}))"}
